// ============================================
// Invoicaty — Shared TypeScript types
// ============================================

export type Language = 'ar' | 'en';
export type BusinessType = 'freelancer' | 'small_business' | 'agency' | 'enterprise';
export type InvoiceStatus = 'Paid' | 'Not Paid' | 'Canceled';
export type UserRole = 'user' | 'admin';

export interface Currency {
  code: string;            // ISO 4217, e.g. "KWD"
  name_en: string;
  name_ar: string;
  symbol: string;          // e.g. "د.ك", "$"
  decimal_places: number;  // 0, 2, 3
}

export interface Country {
  code: string;            // ISO 3166-1 alpha-2, e.g. "KW"
  name_en: string;
  name_ar: string;
  default_currency: string | null;
  default_tax_rate: number;
  phone_code: string | null;
  flag_emoji: string | null;
}

export interface Profile {
  id: string;
  full_name: string;
  business_name: string;
  phone: string;
  email: string;
  bank_name: string;
  bank_account: string;
  bank_iban: string;
  bank_holder: string;
  logo_url: string;
  signature_url: string;
  brand_color: string;

  // i18n / regional fields
  country_code: string | null;
  default_currency: string | null;
  preferred_language: Language;
  tax_rate: number;
  business_type: BusinessType | null;
  onboarding_completed: boolean;
  role: UserRole;

  created_at: string;
  updated_at: string;
}

export interface Invoice {
  id: string;
  user_id: string;
  serial: string;
  date: string;
  client: string;
  project: string;
  description: string;
  amount: number;
  currency: string;          // legacy text field (kept for back-compat)
  currency_code: string;     // new FK
  status: InvoiceStatus;
  category: string;

  // financial fields
  tax_rate: number;
  tax_amount: number;
  discount_amount: number;
  subtotal: number;
  total: number;
  notes: string;

  created_at: string;
  updated_at: string;
}

// ============================================
// Currency formatting helpers
// ============================================
import type { Currency, Language } from './types';

/**
 * Format a number using a currency's locale-aware rules.
 * Falls back gracefully if currency metadata is missing.
 */
export function formatAmount(
  amount: number,
  currency?: Currency | null,
  language: Language = 'ar'
): string {
  const decimals = currency?.decimal_places ?? 2;
  const locale = language === 'ar' ? 'ar' : 'en-US';

  const formatted = new Intl.NumberFormat(locale, {
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals,
  }).format(amount || 0);

  if (!currency) return formatted;

  // Symbol position: Arabic currencies usually come after, Western before
  const isArabicSymbol = /[\u0600-\u06FF]/.test(currency.symbol);
  return isArabicSymbol
    ? `${formatted} ${currency.symbol}`
    : `${currency.symbol} ${formatted}`;
}

/**
 * Compute invoice totals: subtotal → discount → tax → total.
 */
export function computeInvoiceTotals(input: {
  subtotal: number;
  discountAmount?: number;
  taxRate?: number;
}): { subtotal: number; discountAmount: number; taxAmount: number; total: number } {
  const subtotal = Number(input.subtotal) || 0;
  const discountAmount = Number(input.discountAmount) || 0;
  const taxRate = Number(input.taxRate) || 0;

  const taxableBase = Math.max(subtotal - discountAmount, 0);
  const taxAmount = +(taxableBase * (taxRate / 100)).toFixed(3);
  const total = +(taxableBase + taxAmount).toFixed(3);

  return { subtotal, discountAmount, taxAmount, total };
}

/**
 * Round a number to a currency's allowed decimal places.
 */
export function roundToCurrency(amount: number, currency?: Currency | null): number {
  const decimals = currency?.decimal_places ?? 2;
  const factor = Math.pow(10, decimals);
  return Math.round((amount || 0) * factor) / factor;
}

