"use client";
import { useState, useEffect, useCallback } from "react";
import { createClient } from "../../lib/supabase";
import { useRouter } from "next/navigation";
import InvoiceModal from "../../components/InvoiceModal";
import DeleteModal from "../../components/DeleteModal";
import ImportModal from "../../components/ImportModal";
import StatsCards from "../../components/StatsCards";
import InvoiceTable from "../../components/InvoiceTable";
import { printInvoice } from "../../lib/print-invoice";
import Link from "next/link";

export const dynamic = "force-dynamic";

interface Invoice {
  id: string;
  serial: string;
  date: string;
  client: string;
  project: string;
  description: string;
  amount: number;
  discount?: number;
  currency: string;
  status: string;
  category: string;
}

interface Profile {
  full_name: string;
  business_name: string;
  phone: string;
  email: string;
  bank_name: string;
  bank_account: string;
  bank_iban: string;
  bank_holder: string;
  brand_color: string;
  role?: string;
}

export default function DashboardPage() {
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [showDateFilter, setShowDateFilter] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [showImport, setShowImport] = useState(false);
  const [editInvoice, setEditInvoice] = useState<Invoice | null>(null);
  const [deleteInvoice, setDeleteInvoice] = useState<Invoice | null>(null);
  const router = useRouter();
  const supabase = createClient();

  const loadData = useCallback(async () => {
    const { data: { user }, error: authError } = await supabase.auth.getUser();
    if (!user || authError) { router.push("/login"); return; }

    // Force filter by user_id for extra safety
    const [{ data: inv }, { data: prof }] = await Promise.all([
      supabase.from("invoices").select("*").eq("user_id", user.id).order("date", { ascending: false }),
      supabase.from("profiles").select("*").eq("id", user.id).single()
    ]);

    // Auto-create profile if missing
    if (!prof) {
      const { data: newProf } = await supabase.from("profiles").upsert({
        id: user.id,
        full_name: user.user_metadata?.full_name || '',
        email: user.email || '',
      }).select().single();
      setProfile(newProf || null);
    } else {
      setProfile(prof);
    }

    setInvoices(inv || []);
    setLoading(false);
  }, [supabase, router]);

  useEffect(() => { loadData(); }, [loadData]);

  // Re-load when auth state changes (user switch)
  useEffect(() => {
    const { data: { subscription } } = supabase.auth.onAuthStateChange(() => {
      loadData();
    });
    return () => subscription.unsubscribe();
  }, [supabase, loadData]);

  const handleSave = async (data: Partial<Invoice>) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    if (editInvoice) {
      await supabase.from("invoices").update({
        date: data.date,
        client: data.client,
        project: data.project,
        description: data.description,
        amount: data.amount,
        discount: data.discount,
        status: data.status,
        category: data.category,
      }).eq("id", editInvoice.id);
    } else {
      const maxSerial = invoices.reduce((max, inv) => {
        const n = parseInt(inv.serial);
        return !isNaN(n) && n > max ? n : max;
      }, 0);

      await supabase.from("invoices").insert({
        user_id: user.id,
        serial: String(maxSerial + 1).padStart(3, "0"),
        ...data,
      });
    }

    setShowModal(false);
    setEditInvoice(null);
    loadData();
  };

  const handleDelete = async () => {
    if (!deleteInvoice) return;
    await supabase.from("invoices").delete().eq("id", deleteInvoice.id);
    setDeleteInvoice(null);
    loadData();
  };

  const handleImport = async (rows: { date: string; client: string; project: string; description: string; amount: number; status: string; category: string }[]) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    let maxSerial = invoices.reduce((max, inv) => {
      const n = parseInt(inv.serial);
      return !isNaN(n) && n > max ? n : max;
    }, 0);

    const toInsert = rows.map(row => {
      maxSerial++;
      return {
        user_id: user.id,
        serial: String(maxSerial).padStart(3, "0"),
        date: row.date,
        client: row.client,
        project: row.project,
        description: row.description,
        amount: row.amount,
        status: row.status,
        category: row.category,
        currency: "KWD",
      };
    });

    // Insert in batches of 50
    for (let i = 0; i < toInsert.length; i += 50) {
      await supabase.from("invoices").insert(toInsert.slice(i, i + 50));
    }

    setShowImport(false);
    loadData();
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    router.push("/");
  };

  const filtered = invoices.filter(inv => {
    const matchSearch = !search ||
      inv.client.toLowerCase().includes(search.toLowerCase()) ||
      inv.project.toLowerCase().includes(search.toLowerCase()) ||
      inv.serial.includes(search);
    const matchStatus = statusFilter === "all" ||
      (statusFilter === "Paid" && inv.status === "Paid") ||
      (statusFilter === "Not Paid" && inv.status === "Not Paid");
    const matchDateFrom = !dateFrom || inv.date >= dateFrom;
    const matchDateTo = !dateTo || inv.date <= dateTo;
    return matchSearch && matchStatus && matchDateFrom && matchDateTo;
  });

  // Stats
  const now = new Date();
  const totalIncome = invoices.reduce((s, i) => s + (i.status !== "Canceled" ? (Number(i.amount) - (Number(i.discount) || 0)) : 0), 0);
  const monthIncome = invoices.filter(i => {
    const d = new Date(i.date);
    return d.getFullYear() === now.getFullYear() && d.getMonth() === now.getMonth() && i.status !== "Canceled";
  }).reduce((s, i) => s + (Number(i.amount) - (Number(i.discount) || 0)), 0);
  const yearIncome = invoices.filter(i => {
    return new Date(i.date).getFullYear() === now.getFullYear() && i.status !== "Canceled";
  }).reduce((s, i) => s + (Number(i.amount) - (Number(i.discount) || 0)), 0);
  const outstanding = invoices.filter(i => i.status === "Not Paid");
  const outstandingTotal = outstanding.reduce((s, i) => s + (Number(i.amount) - (Number(i.discount) || 0)), 0);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center fade-in">
          <div className="w-10 h-10 border-3 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto mb-3" />
          <p className="text-slate-400 text-sm">جاري التحميل...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-24 md:pb-8">
      {/* Header */}
      <header className="sticky top-0 z-30 glass border-b border-slate-700/50 px-4 py-3 md:px-8 md:py-4">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-2.5">
            <img src="/logo-dark.png" alt="Invoicaty" className="h-8 w-auto" />
            <div>
              <h1 className="text-sm font-bold text-white leading-tight">Invoicaty</h1>
              <p className="text-[10px] text-slate-400">{profile?.full_name || profile?.business_name || 'مرحباً'}</p>
            </div>
          </div>
          <div className="flex items-center gap-1.5">
            {profile?.role === 'admin' && (
              <Link href="/admin"
                className="text-slate-400 hover:text-white p-2 rounded-lg hover:bg-slate-700/50 transition-all text-sm" title="لوحة الإدارة">
                🛡
              </Link>
            )}
            <button onClick={() => setShowImport(true)}
              className="text-slate-400 hover:text-white p-2 rounded-lg hover:bg-slate-700/50 transition-all text-sm" title="استيراد">
              📥
            </button>
            <Link href="/settings"
              className="text-slate-400 hover:text-white p-2 rounded-lg hover:bg-slate-700/50 transition-all text-sm" title="الإعدادات">
              ⚙️
            </Link>
            <button onClick={() => { setEditInvoice(null); setShowModal(true); }}
              className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all flex items-center gap-1.5 shadow-lg shadow-blue-500/20">
              <span>+</span> <span className="hidden sm:inline">فاتورة جديدة</span><span className="sm:hidden">جديدة</span>
            </button>
            <button onClick={handleLogout}
              className="text-slate-400 hover:text-white p-2 rounded-lg hover:bg-slate-700/50 transition-all text-sm" title="خروج">
              ⬅️
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 md:px-8 pt-5">
        {/* Stats */}
        <StatsCards
          total={totalIncome}
          month={monthIncome}
          year={yearIncome}
          outstanding={outstandingTotal}
          outstandingCount={outstanding.length}
        />

        {/* Filters */}
        <div className="mt-6 flex flex-col sm:flex-row gap-3">
          <div className="relative flex-1">
            <span className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 text-sm">🔍</span>
            <input type="text" value={search} onChange={e => setSearch(e.target.value)}
              placeholder="بحث بالعميل أو المشروع أو الرقم..."
              className="w-full bg-slate-800/50 border border-slate-700/50 rounded-xl pr-9 pl-4 py-3 text-sm text-white placeholder:text-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500/40" />
          </div>
          <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)}
            className="bg-slate-800/50 border border-slate-700/50 rounded-xl px-4 py-3 text-sm text-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-500/40 min-w-[140px]">
            <option value="all">كل الحالات</option>
            <option value="Paid">مدفوع ✅</option>
            <option value="Not Paid">معلق 🚩</option>
          </select>
          <button onClick={() => setShowDateFilter(!showDateFilter)}
            className={`flex items-center gap-1.5 px-4 py-3 rounded-xl text-xs font-bold transition-all border ${
              dateFrom || dateTo
                ? "bg-blue-500/15 border-blue-500/30 text-blue-400"
                : "bg-slate-800/50 border-slate-700/50 text-slate-400 hover:bg-slate-700/50"
            }`}>
            📅 {dateFrom || dateTo ? "فلتر مفعّل" : "تاريخ"}
          </button>
          <div className="flex items-center justify-center gap-1.5 bg-slate-800/30 rounded-xl px-4 py-3 border border-slate-700/30 min-w-[100px]">
            <span className="text-slate-500 text-xs">النتائج:</span>
            <span className="font-inter font-bold text-blue-400">{filtered.length}</span>
          </div>
        </div>

        {/* Date Range Filter */}
        {showDateFilter && (
          <div className="mt-3 flex flex-col sm:flex-row items-stretch sm:items-center gap-3 glass rounded-xl p-4 fade-in">
            <div className="flex items-center gap-2 flex-1">
              <label className="text-slate-400 text-xs font-bold whitespace-nowrap">من:</label>
              <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)}
                className="flex-1 bg-slate-800/50 border border-slate-700/50 rounded-xl px-3 py-2.5 text-sm text-white font-inter focus:outline-none focus:ring-2 focus:ring-blue-500/40" />
            </div>
            <div className="flex items-center gap-2 flex-1">
              <label className="text-slate-400 text-xs font-bold whitespace-nowrap">إلى:</label>
              <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)}
                className="flex-1 bg-slate-800/50 border border-slate-700/50 rounded-xl px-3 py-2.5 text-sm text-white font-inter focus:outline-none focus:ring-2 focus:ring-blue-500/40" />
            </div>
            {(dateFrom || dateTo) && (
              <button onClick={() => { setDateFrom(""); setDateTo(""); }}
                className="bg-red-500/10 border border-red-500/20 text-red-400 px-4 py-2.5 rounded-xl text-xs font-bold hover:bg-red-500/20 transition-all">
                ✕ مسح
              </button>
            )}
          </div>
        )}

        {/* Table */}
        <InvoiceTable
          invoices={filtered}
          onEdit={(inv) => { setEditInvoice(inv); setShowModal(true); }}
          onDelete={(inv) => setDeleteInvoice(inv)}
          onPrint={(inv) => printInvoice(inv, profile)}
        />
      </main>

      {/* Mobile FAB */}
      <button onClick={() => { setEditInvoice(null); setShowModal(true); }}
        className="md:hidden fixed bottom-6 right-6 w-14 h-14 bg-gradient-to-br from-blue-600 to-purple-600 rounded-2xl shadow-2xl shadow-blue-500/30 flex items-center justify-center text-white text-2xl z-20 active:scale-95 transition-transform safe-bottom">
        +
      </button>

      {/* Modals */}
      {showModal && (
        <InvoiceModal
          invoice={editInvoice}
          onSave={handleSave}
          onClose={() => { setShowModal(false); setEditInvoice(null); }}
        />
      )}
      {deleteInvoice && (
        <DeleteModal
          serial={deleteInvoice.serial}
          onConfirm={handleDelete}
          onClose={() => setDeleteInvoice(null)}
        />
      )}
      {showImport && (
        <ImportModal
          onImport={handleImport}
          onClose={() => setShowImport(false)}
        />
      )}
    </div>
  );
}

"use client";
import { useState } from "react";
import { createClient } from "../../lib/supabase";
import Link from "next/link";
import { useRouter } from "next/navigation";

export default function RegisterPage() {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [confirmEmail, setConfirmEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState(false);
  const router = useRouter();
  const supabase = createClient();

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    if (email !== confirmEmail) {
      setError("البريد الإلكتروني غير متطابق");
      return;
    }
    if (password.length < 6) { setError("كلمة المرور يجب أن تكون 6 أحرف على الأقل"); return; }
    setLoading(true);
    setError("");

    const { error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        data: { full_name: name },
        emailRedirectTo: `${window.location.origin}/auth/callback`,
      }
    });

    if (error) {
      setError(error.message === "User already registered" ? "هذا البريد مسجل مسبقاً" : error.message);
      setLoading(false);
    } else {
      setLoading(false);
      setSuccess(true);
    }
  };

  if (success) {
    return (
      <div className="min-h-screen flex items-center justify-center px-5">
        <div className="glass rounded-3xl p-10 text-center fade-in max-w-sm border-t-4 border-green-500">
          <div className="text-6xl mb-6">📩</div>
          <h2 className="text-2xl font-bold text-white mb-3">تفعيل الحساب</h2>
          <p className="text-slate-300 text-sm mb-2">أرسلنا رابط تفعيل إلى:</p>
          <p className="text-blue-400 font-bold text-base mb-6" dir="ltr">{email}</p>
          <div className="bg-blue-500/10 border border-blue-500/20 rounded-2xl p-4 mb-8">
            <p className="text-slate-400 text-xs leading-relaxed">
              يرجى فتح بريدك الإلكتروني والضغط على الرابط لتفعيل حسابك. إذا لم تجد الرسالة، افحص صندوق الـ <span className="text-white font-bold">Spam</span>.
            </p>
          </div>
          <div className="space-y-3">
            <a href="https://mail.google.com" target="_blank" rel="noreferrer" className="block w-full bg-white text-slate-900 py-3.5 rounded-xl text-sm font-bold transition-all hover:bg-slate-200">
              فتح Gmail
            </a>
            <Link href="/login" className="block w-full bg-slate-800 text-slate-300 py-3.5 rounded-xl text-sm font-bold transition-all hover:bg-slate-700">
              العودة لتسجيل الدخول
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center px-5 py-10">
      <div className="fixed inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/4 right-1/4 w-72 h-72 bg-purple-500/10 rounded-full blur-3xl" />
        <div className="absolute bottom-1/4 left-1/4 w-72 h-72 bg-blue-500/8 rounded-full blur-3xl" />
      </div>
      <div className="glass rounded-3xl p-8 w-full max-w-sm relative z-10 fade-in">
        <div className="text-center mb-8">
          <img src="/logo-dark.png" alt="Invoicaty" className="w-16 h-20 mx-auto mb-4" />
          <h1 className="text-2xl font-bold text-white">حساب جديد</h1>
          <p className="text-slate-400 text-sm mt-1">ابدأ بإدارة فواتيرك مجاناً</p>
        </div>

        <form onSubmit={handleRegister} className="space-y-4">
          <div>
            <label className="block text-xs font-bold text-slate-400 mb-2">الاسم الكامل</label>
            <input type="text" value={name} onChange={e => setName(e.target.value)} required
              placeholder="اسمك الكامل"
              className="w-full bg-slate-800/50 border border-slate-600/30 rounded-xl px-4 py-3.5 text-sm text-white placeholder:text-slate-500 focus:ring-2 focus:ring-purple-500/50 outline-none" />
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-400 mb-2">البريد الإلكتروني</label>
            <input type="email" value={email} onChange={e => setEmail(e.target.value)} required
              placeholder="email@example.com" dir="ltr"
              className="w-full bg-slate-800/50 border border-slate-600/30 rounded-xl px-4 py-3.5 text-sm text-white placeholder:text-slate-500 focus:ring-2 focus:ring-purple-500/50 outline-none" />
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-400 mb-2">تأكيد البريد الإلكتروني</label>
            <input type="email" value={confirmEmail} onChange={e => setConfirmEmail(e.target.value)} required
              placeholder="تأكيد البريد الإلكتروني" dir="ltr"
              className="w-full bg-slate-800/50 border border-slate-600/30 rounded-xl px-4 py-3.5 text-sm text-white placeholder:text-slate-500 focus:ring-2 focus:ring-purple-500/50 outline-none" />
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-400 mb-2">كلمة المرور</label>
            <input type="password" value={password} onChange={e => setPassword(e.target.value)} required
              placeholder="6 أحرف على الأقل" dir="ltr"
              className="w-full bg-slate-800/50 border border-slate-600/30 rounded-xl px-4 py-3.5 text-sm text-white placeholder:text-slate-500 focus:ring-2 focus:ring-purple-500/50 outline-none" />
          </div>

          {error && <p className="text-red-400 text-xs text-center">{error}</p>}

          <button type="submit" disabled={loading}
            className="w-full bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 text-white font-bold py-4 rounded-xl shadow-lg shadow-purple-500/20 transition-all disabled:opacity-50 text-base">
            {loading ? "جاري التسجيل..." : "إنشاء حساب"}
          </button>
        </form>

        <p className="text-center text-slate-400 text-sm mt-6">
          عندك حساب؟{" "}
          <Link href="/login" className="text-purple-400 font-bold hover:underline">سجّل دخولك</Link>
        </p>
      </div>
    </div>
  );
}

"use client";
import { useState, useEffect } from "react";
import { createClient } from "../../lib/supabase";
import { useRouter } from "next/navigation";
import Link from "next/link";

const TEMPLATES = [
  { id: "classic", name: "كلاسيكي", desc: "قالب أنيق واحترافي", preview: "📄" },
  { id: "modern", name: "عصري", desc: "تصميم حديث وبسيط", preview: "🎨" },
  { id: "minimal", name: "بسيط", desc: "الأقل عناصر، الأكثر وضوحاً", preview: "✨" },
];

const COLORS = [
  { value: "#f04444", name: "أحمر" },
  { value: "#3b82f6", name: "أزرق" },
  { value: "#8b5cf6", name: "بنفسجي" },
  { value: "#10b981", name: "أخضر" },
  { value: "#f59e0b", name: "ذهبي" },
  { value: "#ec4899", name: "وردي" },
  { value: "#1e293b", name: "داكن" },
  { value: "#0ea5e9", name: "سماوي" },
];

interface Profile {
  id: string;
  full_name: string;
  business_name: string;
  phone: string;
  email: string;
  bank_name: string;
  bank_account: string;
  bank_iban: string;
  bank_holder: string;
  brand_color: string;
  logo_url: string;
}

export default function SettingsPage() {
  const [profile, setProfile] = useState<Profile | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);
  const [tab, setTab] = useState<"profile" | "invoice">("profile");

  // Form fields
  const [fullName, setFullName] = useState("");
  const [businessName, setBusinessName] = useState("");
  const [phone, setPhone] = useState("");
  const [email, setEmail] = useState("");
  const [bankName, setBankName] = useState("");
  const [bankAccount, setBankAccount] = useState("");
  const [bankIban, setBankIban] = useState("");
  const [bankHolder, setBankHolder] = useState("");
  const [brandColor, setBrandColor] = useState("#f04444");
  const [template, setTemplate] = useState("classic");

  const router = useRouter();
  const supabase = createClient();

  useEffect(() => {
    (async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) { router.push("/login"); return; }

      const { data } = await supabase.from("profiles").select("*").eq("id", user.id).single();
      if (data) {
        setProfile(data);
        setFullName(data.full_name || "");
        setBusinessName(data.business_name || "");
        setPhone(data.phone || "");
        setEmail(data.email || user.email || "");
        setBankName(data.bank_name || "");
        setBankAccount(data.bank_account || "");
        setBankIban(data.bank_iban || "");
        setBankHolder(data.bank_holder || "");
        setBrandColor(data.brand_color || "#f04444");
      }
      setLoading(false);
    })();
  }, [supabase, router]);

  const handleSave = async () => {
    if (!profile) return;
    setSaving(true);
    setSaved(false);

    await supabase.from("profiles").update({
      full_name: fullName,
      business_name: businessName,
      phone,
      email,
      bank_name: bankName,
      bank_account: bankAccount,
      bank_iban: bankIban,
      bank_holder: bankHolder,
      brand_color: brandColor,
      updated_at: new Date().toISOString(),
    }).eq("id", profile.id);

    setSaving(false);
    setSaved(true);
    setTimeout(() => setSaved(false), 3000);
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
