                <td className="p-4 font-inter text-slate-400 text-sm">{inv.date}</td>
                <td className="p-4 font-bold text-white text-sm">{inv.client}</td>
                <td className="p-4 text-slate-300 text-xs max-w-[200px] truncate">{inv.project}</td>
