        id: user.id, full_name: user.user_metadata?.full_name || '', email: user.email || '',
      }).select().single();
      setProfile(newProf || null);
    } else {
      setProfile(prof);
      // Load currency symbol
      if (prof.default_currency) {
        const { data: curr } = await supabase.from("currencies").select("symbol").eq("code", prof.default_currency).single();
        if (curr?.symbol) setCurrencySymbol(curr.symbol);
      }
    }

    setInvoices(inv || []);
    setLoading(false);
  }, [supabase, router]);

  useEffect(() => { loadData(); }, [loadData]);

  useEffect(() => {
    const { data: { subscription } } = supabase.auth.onAuthStateChange(() => { loadData(); });
    return () => subscription.unsubscribe();
  }, [supabase, loadData]);

